def test_local_app_routes_render_modern_workflow_and_health(
    tmp_path: Path,
) -> None:
    AgentSystem(tmp_path).initialize()
    workflow_file = tmp_path / ".github" / "workflows" / "tests.yml"
    workflow_file.parent.mkdir(parents=True, exist_ok=True)
    workflow_file.write_text(
        "\n".join(
            [
                "name: Tests",
                "on:",
                "  push:",
                "    branches:",
                "      - main",
                "      - \"codex/**\"",
                "  pull_request:",
                "    branches: [main]",
                "  workflow_dispatch:",
                "jobs:",
                "  smoke:",
                "    timeout-minutes: 10",
                "    steps:",
                "      - name: Compile source and tests",
                "        run: python -m compileall -q agent_os tests",
                "      - name: Run local CLI smoke checks",
                "        run: python -m agent_os.cli --root \"$CLANKEROS_CI_ROOT\" app-smoke-test",
                "        run: python -m agent_os.cli --root \"$CLANKEROS_CI_ROOT\" app-demo-smoke-test",
                "      - name: Check whitespace",
                "        run: git diff --check",
                "  full-suite:",
                "    needs: smoke",
                "    timeout-minutes: 45",
                "    steps:",
                "      - name: Run full test suite",
                "        run: python -m pytest -q",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    ci_evidence_path = tmp_path / ".clanker" / "ci" / "github-actions-123.json"
    ci_evidence_path.parent.mkdir(parents=True, exist_ok=True)
    ci_evidence_path.write_text(
        json.dumps(
            {
                "status": "success",
                "network_actions_taken": 0,
                "external_mutations_taken": 0,
            }
        )
        + "\n",
        encoding="utf-8",
    )
    storage = Storage(tmp_path / ".agent" / "state.db")
    handoff_evidence_path = tmp_path / ".clanker" / "github" / "handoff-demo.json"
    handoff_evidence_path.parent.mkdir(parents=True, exist_ok=True)
