def test_local_app_demo_scenario_populates_fixture_state(
    tmp_path: Path,
) -> None:
    result = run_demo_app_scenario(tmp_path)
    goal_title = "Demo the ClankerOS local operator app with fixture-backed state"

    assert result.project_id == "local-app-demo"
    assert result.project_root.exists()
    assert result.handoff_md.exists()
    assert result.coder_prep_md.exists()
    assert result.coder_worktree_plan_md.exists()
    assert result.approval_id.startswith("coder_worktree_approval_")
    assert result.execution_approval_id.startswith("coder_worktree_approval_")
    assert result.execution_approval_id != result.approval_id
    assert result.coder_worktree_run_id.startswith("run_")
    assert result.review_path.exists()
    assert result.coder_worktree_run_id in result.review_path.read_text(encoding="utf-8")

    project_commit = subprocess.run(
        ["git", "rev-parse", "HEAD"],
        cwd=result.project_root,
        check=True,
        capture_output=True,
        text=True,
    ).stdout.strip()
    project_branch = subprocess.run(
        ["git", "branch", "--show-current"],
        cwd=result.project_root,
        check=True,
        capture_output=True,
        text=True,
    ).stdout.strip() or "unknown"
    ci_evidence_path = tmp_path / ".clanker" / "ci-snapshots" / "demo-goal-ci.json"
