def _table_counts(tmp_path: Path, tables: list[str]) -> dict[str, int]:
    with sqlite3.connect(tmp_path / ".agent" / "state.db") as connection:
        counts: dict[str, int] = {}
        for table in tables:
            row = connection.execute(f"select count(*) from {table}").fetchone()
            counts[table] = int(row[0])
        return counts


