def _create_registered_context_pack_delegation(
    tmp_path: Path,
    capsys,
) -> tuple[Storage, str, str, str, Path]:
    repo_path = tmp_path / "subject-repo"
    _init_git_repo(repo_path)
    files = {
        "agent_os/delegation_runner.py": (
            "def run_delegation():\n"
            "    repo_scouting = True\n"
            "    context_pack = 'context-pack'\n"
            "    subject_marker = 'delegation runner context pack'\n"
        ),
        "agent_os/cli.py": (
            "def build_parser():\n"
            "    return 'context-pack profile-adapter run-delegation'\n"
        ),
        "tests/test_delegation_runner.py": (
            "def test_context_pack_scouting():\n"
            "    assert 'context-pack' and 'delegation_runner'\n"
        ),
        "docs/tutorial-executable-delegation.md": (
            "# Executable Delegation\n\n"
            "Use context-pack before run-delegation for repo scouting.\n"
        ),
        "pyproject.toml": "[project]\nname = 'subject'\n",
        ".env": "CONTEXT_PACK_SECRET=do-not-read\n",
        "credentials.txt": "context-pack credentials should be skipped\n",
        "node_modules/ignored.js": "context-pack ignored directory hit\n",
    }
    for relative_path, content in files.items():
        path = repo_path / relative_path
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8")
    subprocess.run(["git", "add", "."], cwd=repo_path, check=True)
    subprocess.run(
        ["git", "commit", "-m", "add context pack subject files"],
        cwd=repo_path,
        check=True,
        capture_output=True,
    )
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "register-project",
                "subject",
                "--path",
                str(repo_path),
                "--test-command",
                "python3 -m pytest -q",
            ]
        )
        == 0
    )
    capsys.readouterr()

    storage = Storage(tmp_path / ".agent" / "state.db")
    storage.initialize()
    goal_id = storage.create_goal(
        "subject",
        "Make context-pack repo scouting useful for delegation_runner work",
    )
    task_id = storage.create_task(
        goal_id=goal_id,
        project_id="subject",
        task_type="record_learning",
        description=(
            "Find relevant delegation_runner implementation files and tests "
            "for context-pack repo scouting."
        ),
        verification_plan={
            "type": "manual_review",
            "command": "python3 -m pytest tests/test_delegation_runner.py -q",
        },
    )
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "delegate",
                task_id,
                "--profile",
                "scout",
                "--title",
                "Find relevant delegation_runner files and tests for context-pack",
            ]
        )
        == 0
    )
    capsys.readouterr()
    delegation_id = storage.list_subagent_delegations(goal_id)[0].id
    return storage, goal_id, task_id, delegation_id, repo_path


def _write_coder_worktree_subject_scripts(repo_path: Path) -> None:
    scripts_dir = repo_path / "scripts"
    scripts_dir.mkdir(parents=True, exist_ok=True)
    (scripts_dir / "change_allowed.py").write_text(
        "\n".join(
            [
                "from pathlib import Path",
                "",
                "target = Path('agent_os/delegation_runner.py')",
                "text = target.read_text(encoding='utf-8')",
                "target.write_text(text + \"\\nallowed_change = 'allowed-change'\\n\", encoding='utf-8')",
                "print('allowed-change')",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    (scripts_dir / "change_outside.py").write_text(
        "\n".join(
            [
                "from pathlib import Path",
                "",
                "target = Path('notes/outside.txt')",
                "target.parent.mkdir(parents=True, exist_ok=True)",
                "target.write_text('outside-change\\n', encoding='utf-8')",
                "print('outside-change')",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    (scripts_dir / "fail_verify.py").write_text(
        "import sys\nprint('verification-failed')\nsys.exit(7)\n",
        encoding="utf-8",
    )
    subprocess.run(["git", "add", "scripts"], cwd=repo_path, check=True)
    subprocess.run(
        ["git", "commit", "--amend", "--no-edit"],
        cwd=repo_path,
        check=True,
        capture_output=True,
    )


def _run_completed_coder_worktree(
    tmp_path: Path,
    capsys,
) -> tuple[str, str, str, str, Path, Path, Path]:
    _storage, _goal_id, _task_id, delegation_id, repo_path = (
        _create_registered_context_pack_delegation(tmp_path, capsys)
    )
    _write_coder_worktree_subject_scripts(repo_path)
    source_run_id = _run_fake_context_pack_scout(tmp_path, capsys, delegation_id)
    _prepare_coder_worktree_plan(tmp_path, capsys, delegation_id)
    approval_id = _request_and_approve_coder_worktree(tmp_path, capsys, delegation_id)
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "run-coder-worktree",
                delegation_id,
                "--command",
                "python3 scripts/change_allowed.py",
                "--verify",
            ]
        )
        == 0
    )
    run_output = capsys.readouterr().out
    assert "coder_worktree_run: completed" in run_output
    assert "changed_files_within_allowed_files: true" in run_output
    assert "commit_created: false" in run_output
    run_id = next(
        line.split(": ", 1)[1]
        for line in run_output.splitlines()
        if line.startswith("run_id: ")
    )
    evidence_dir = tmp_path / next(
        line.split(": ", 1)[1]
        for line in run_output.splitlines()
        if line.startswith("evidence: ")
    )
    worktree_path = Path(
        next(
            line.split(": ", 1)[1]
            for line in run_output.splitlines()
            if line.startswith("worktree_path: ")
        )
    )
    return (
        source_run_id,
        delegation_id,
        approval_id,
        run_id,
        evidence_dir,
        worktree_path,
        repo_path,
    )


