def _request_and_approve_coder_worktree(
    tmp_path: Path,
    capsys,
    delegation_id: str,
    *,
    force_new: bool = False,
) -> str:
    request_args = [
        "--root",
        str(tmp_path),
        "coder-worktree-approval",
        delegation_id,
        "--requested-by",
        "operator",
        "--note",
        "Approve bounded worktree execution",
    ]
    if force_new:
        request_args.append("--force-new")
    assert main(request_args) == 0
    request_output = capsys.readouterr().out
    approval_id = next(
        line.split(": ", 1)[1]
        for line in request_output.splitlines()
        if line.startswith("approval_id: ")
    )
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "approve-coder-worktree",
                approval_id,
                "--decided-by",
                "operator",
                "--note",
                "Approved bounded execution",
            ]
        )
        == 0
    )
    capsys.readouterr()
    return approval_id


def _write_fake_scout_adapter(tmp_path: Path) -> Path:
    adapter_path = tmp_path / ".clanker" / "adapters" / "fake_scout.py"
    adapter_path.parent.mkdir(parents=True, exist_ok=True)
    adapter_path.write_text(
        "\n".join(
            [
                "import json",
                "import sys",
                "from pathlib import Path",
                "",
                "input_path = Path(sys.argv[1])",
                "payload = json.loads(input_path.read_text(encoding='utf-8'))",
                "evidence_dir = Path(payload['evidence_dir'])",
                "(evidence_dir / 'adapter-seen.txt').write_text(payload['delegation']['id'], encoding='utf-8')",
                "print(json.dumps({",
                "  'result_summary': 'Found relevant CLI files.',",
                "  'structured_output': {",
                "    'files': ['agent_os/cli.py'],",
                "    'findings': ['CLI command parser lives in agent_os/cli.py.'],",
                "    'relevant_files': ['agent_os/cli.py']",
                "  }",
                "}))",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    return adapter_path


def _configure_scout_adapter(
    tmp_path: Path,
    capsys,
    adapter_path: Path,
    *,
    working_directory: str | None = None,
) -> None:
    args = [
        "--root",
        str(tmp_path),
        "profile-adapter",
        "scout",
        "--command",
        f"python3 {adapter_path}",
        "--input-mode",
        "json_file",
        "--output-mode",
        "json",
        "--timeout-seconds",
        "30",
    ]
    if working_directory:
        args.extend(["--working-directory", working_directory])
    assert (
        main(args)
        == 0
    )
    capsys.readouterr()


def _init_git_repo(repo_path: Path) -> None:
    repo_path.mkdir(exist_ok=True)
    subprocess.run(["git", "init"], cwd=repo_path, check=True, capture_output=True)
    subprocess.run(
        ["git", "config", "user.email", "clankeros@example.invalid"],
        cwd=repo_path,
        check=True,
        capture_output=True,
    )
    subprocess.run(
        ["git", "config", "user.name", "ClankerOS Test"],
        cwd=repo_path,
        check=True,
        capture_output=True,
    )
    subprocess.run(
        ["git", "config", "commit.gpgsign", "false"],
        cwd=repo_path,
        check=True,
        capture_output=True,
    )
    (repo_path / "README.md").write_text("# Subject\n", encoding="utf-8")
    subprocess.run(["git", "add", "README.md"], cwd=repo_path, check=True)
    subprocess.run(
        ["git", "commit", "-m", "initial"],
        cwd=repo_path,
        check=True,
        capture_output=True,
    )


def test_failed_verification_records_incident_and_dashboard_visibility(tmp_path: Path) -> None:
    system = CorruptingAgentSystem(tmp_path)

    result = system.run_goal(
        project_id="bootstrap",
        description="Trigger failed verification incident",
    )

    assert result.status == "failed"
    storage = Storage(tmp_path / ".agent" / "state.db")
    incidents = storage.list_recent_incidents()
    assert len(incidents) == 1
    incident = incidents[0]
    assert incident.run_id == result.run_id
    assert incident.project_id == "bootstrap"
    assert incident.status == "open"
    assert incident.severity == "high"
    assert incident.incident_type == "verification_failed"
    assert incident.failure_class == "bad verification"
    assert "failed verification" in incident.summary
    assert incident.evidence["passed"] is False
    assert incident.failed_checks == ["contains_goal"]
    assert incident.evidence_path is not None
    assert Path(incident.evidence_path).exists()

    events = [json.loads(line) for line in result.events_path.read_text().splitlines()]
    event_types = {event["event_type"] for event in events}
    assert "incident.opened" in event_types
    task_failed = [event for event in events if event["event_type"] == "task.failed"][0]
    assert task_failed["payload"]["incident_id"] == incident.id

    dashboard_path = generate_static_dashboard(tmp_path)
    dashboard = dashboard_path.read_text(encoding="utf-8")
    assert "## Incidents" in dashboard
    assert "- open: 1" in dashboard
    assert incident.id in dashboard
    assert "verification_failed" in dashboard
    assert result.run_id in dashboard
    assert "contains_goal" in dashboard


